import { snakeCase, uuid, varchar } from 'drizzle-orm/pg-core';
import { appConfig } from 'shared';
import { generateId } from 'shared/entity-id';
import { usersTable } from '#/db/schema/users';
import { timestampColumns } from '#/db/utils/timestamp-columns';

const roleEnum = appConfig.systemRoles;

export const systemRolesTable = snakeCase.table('system_roles', {
  id: uuid().primaryKey().$defaultFn(generateId),
  userId: uuid()
    .notNull()
    .unique()
    .references(() => usersTable.id, { onDelete: 'cascade' }),
  role: varchar({ enum: roleEnum }).notNull(),
  createdAt: timestampColumns.createdAt,
  updatedAt: timestampColumns.updatedAt,
});

export type SystemRoleModel = typeof systemRolesTable.$inferSelect;
export type InsertSystemRoleModel = typeof systemRolesTable.$inferInsert;

import type { ContextEntityType } from 'shared';
import type { AuthContext } from '#/core/context';
import { AppError } from '#/core/error';
import { baseDb } from '#/db/db';
import { invalidateCache } from '#/middlewares/guard/invalidate-cache';
import { resolveEntity } from '#/modules/entities/entities-queries';
import { deleteMyMembership } from '#/modules/me/me-queries';
import { logEvent } from '#/utils/logger';

export async function deleteMyMembershipOp(ctx: AuthContext, entityType: ContextEntityType, entityId: string) {
  const user = ctx.var.user;

  const entity = await resolveEntity(ctx, entityType, entityId);
  if (!entity) throw new AppError(404, 'not_found', 'warn', { entityType });

  await deleteMyMembership({ var: { ...ctx.var, db: baseDb } }, { contextId: entity.id });

  invalidateCache.user(user.id);
  logEvent(ctx, 'info', 'User left entity');
}

import type { AuthContext } from '#/core/context';
import { findUserById, upsertLastStarted } from '#/modules/me/me-queries';
import { getIsoDate } from '#/utils/iso-date';

const THROTTLE_MS = 60 * 1000; // 1 minute
const lastStartedMemory = new Map<string, number>();

export async function getMeOp(ctx: AuthContext) {
  const isSystemAdmin = ctx.var.isSystemAdmin;
  const userId = ctx.var.userId;

  // Throttle lastStartedAt upsert — fire-and-forget like lastSeenAt
  const now = Date.now();
  const last = lastStartedMemory.get(userId) ?? 0;
  if (now - last >= THROTTLE_MS) {
    lastStartedMemory.set(userId, now);
    const lastStartedAt = getIsoDate();
    upsertLastStarted(ctx, { lastStartedAt }).catch(() => {
      lastStartedMemory.delete(userId);
    });
  }

  const user = await findUserById(ctx);

  return { user, isSystemAdmin };
}

